document.addEventListener("DOMContentLoaded", function() {
    document.body.addEventListener("click", function(event) {
        const shareButton = event.target.closest(".native-share");
        if (!shareButton) return;

        if (navigator.share) {
            navigator.share({
                url: window.location.href
            }).catch((error) => {
            });
        } else {
            shareButton.style.display = "none";
        }
    });
});

body.script:
(function () {
    function applyAdmin(data) {
        if (data && data.isAdmin) {
            document.querySelectorAll('.admin-ad-space-box').forEach(function (el) { el.style.display = ''; });
        }
    }
    function tryRun(retries) {
        if (window.__userInfoPromise) {
            window.__userInfoPromise.then(applyAdmin);
            return;
        }
        if (retries > 60) {
            window.__userInfoPromise = fetch('/api/user-info', { cache: 'no-store', credentials: 'same-origin', priority: 'low' })
                .then(function (r) { return r.json(); })
                .catch(function () { return {}; });
            window.__userInfoPromise.then(applyAdmin);
            return;
        }
        setTimeout(function () { tryRun(retries + 1); }, 50);
    }
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function () { tryRun(0); });
    } else {
        tryRun(0);
    }
})();

document.addEventListener('alpine:init', () => {
    Alpine.data('voiceSearch', () => ({
        searchText: '',
        recognition: null,
        isRecording: false,
        timeout: null,

        init() {
            if (!('webkitSpeechRecognition' in window)) {
                console.warn('Tarayıcınız sesli aramayı desteklemiyor.');
                return;
            }

            this.recognition = new webkitSpeechRecognition();
            this.recognition.lang = 'tr-TR';
            this.recognition.interimResults = false;
            this.recognition.maxAlternatives = 1;

            this.recognition.onstart = () => {
                this.isRecording = true;
                this.timeout = setTimeout(() => {
                    if (this.isRecording) {
                        this.recognition.stop();
                    }
                }, 15000);
            };

            this.recognition.onend = () => {
                this.isRecording = false;
                clearTimeout(this.timeout);

            };

            this.recognition.onresult = (event) => {
                const transcript = event.results[0][0].transcript;
                this.searchText = transcript;
                const input = document.getElementById('q');
                if (input) {
                    input.value = transcript;
                    input.focus();
                }

                const form = document.querySelector('form[action*="/arama"]');
                if (form && transcript.length >= 3) {
                    setTimeout(() => form.submit(), 500);
                }
            };

            this.recognition.onerror = (event) => {
                this.isRecording = false;
                clearTimeout(this.timeout);
                console.error('Ses tanıma hatası:', event.error);
            };
        },

        startVoiceSearch() {
            if (this.isRecording) {
                this.recognition.stop();
                return;
            }

            this.recognition.start();
        }
    }));
});

