(function () {
    const logos = {
        desktop: {
            light: 'https://www.canakkalekalem.com/images/generals/logo.png?v=1873',
            dark: 'https://www.canakkalekalem.com/images/generals/logo-night.png?v=1873',
        },
        mobile: {
            light: 'https://www.canakkalekalem.com/images/generals/mobil-logo.png?v=1873',
            dark: 'https://www.canakkalekalem.com/images/generals/mobil-logo-night.png?v=1873',
        }
    };

    function updateLogos() {
        const darkMode = localStorage.getItem('darkMode') === 'true';
        const isMobile = window.innerWidth < 768;

        document.documentElement.classList.toggle('dark', darkMode);

        const src = isMobile
            ? (darkMode ? logos.mobile.dark : logos.mobile.light)
            : (darkMode ? logos.desktop.dark : logos.desktop.light);

        ['siteLogo', 'siteLogoTop'].forEach(id => {
            const el = document.getElementById(id);
            if (el && el.src !== src) {
                el.src = src;
            }
        });
    }

    document.readyState === 'loading'
        ? document.addEventListener('DOMContentLoaded', updateLogos)
        : updateLogos();

    window.addEventListener('resize', updateLogos);

    window.addEventListener('storage', e => {
        if (e.key === 'darkMode') updateLogos();
    });

    const _setItem = localStorage.setItem;
    localStorage.setItem = function (k, v) {
        _setItem.apply(this, arguments);
        if (k === 'darkMode') updateLogos();
    };
})();

function ccConsent() {
    const STORAGE_KEY = 'cc_consent_v2';
    const VERSION = 2;
    const MAX_AGE_MS = 180 * 24 * 60 * 60 * 1000;

    return {
        visible: false,
        showDetails: false,
        expanded: false,
        prefs: { functionality: false, ads: false, personalization: false },

        init() {
            try {
                const raw = localStorage.getItem(STORAGE_KEY);
                if (!raw) { this.visible = true; return; }
                const data = JSON.parse(raw);
                if (data.version !== VERSION) { this.visible = true; return; }
                if (!data.ts || (Date.now() - data.ts) > MAX_AGE_MS) { this.visible = true; return; }
                this.applyToGtag({
                    functionality:   !!data.functionality,
                    ads:             !!data.ads,
                    personalization: !!data.personalization,
                });
            } catch (e) { this.visible = true; }
        },

        acceptAll() { this.persist({ functionality: true, ads: true, personalization: true }); },
        rejectAll() { this.persist({ functionality: false, ads: false, personalization: false }); },
        saveCustom() {
            this.persist({
                functionality:   !!this.prefs.functionality,
                ads:             !!this.prefs.ads,
                personalization: !!this.prefs.personalization,
            });
        },

        persist(p) {
            try {
                localStorage.setItem(STORAGE_KEY, JSON.stringify({ version: VERSION, ts: Date.now(), ...p }));
            } catch (e) {}
            this.applyToGtag(p);
            this.visible = false;
        },

        applyToGtag(p) {
            if (typeof window.gtag !== 'function') {
                window.dataLayer = window.dataLayer || [];
                window.gtag = function () { window.dataLayer.push(arguments); };
            }
            window.gtag('consent', 'update', {
                'functionality_storage':   p.functionality   ? 'granted' : 'denied',
                'personalization_storage': p.personalization ? 'granted' : 'denied',
                'ad_storage':              p.ads             ? 'granted' : 'denied',
                'ad_user_data':            p.ads             ? 'granted' : 'denied',
                'ad_personalization':      p.personalization ? 'granted' : 'denied',
            });
        },
    };
}

window.resetCookieConsent = function () {
    try { localStorage.removeItem('cc_consent_v2'); } catch (e) {}
    location.reload();
};

