function counter($el, n) {
    (function loop() {
        $el.innerHTML = n;
        if (n--) {
            setTimeout(loop, 1000);
        } else if (n <= 0) {
            location.replace("https://www.canakkalekalem.com");
        }
    })();
}

window.addEventListener("load", function () {
    counter(document.getElementById("countdown"), 5);
});

window.dataLayer = window.dataLayer || [];

function gtag() {
    dataLayer.push(arguments);
}

