(function () {
    if (window.__userInfoPromise) return;

    var hasLoginCookie = document.cookie.indexOf('user_logged_in=1') !== -1;
    var hasPremiumPost = !!(window.__post && window.__post.private === 1);
    var subEnabled = false;

    if (! hasLoginCookie && ! (hasPremiumPost && subEnabled)) {
        window.__userInfoPromise = Promise.resolve({
            isLoggedIn: false,
            isAdmin: false,
            name: 'Ziyaretçi',
            accessibleFeatures: [],
            subscriptionStatus: subEnabled ? 1 : 0,
            __status: 200
        });
        return;
    }

    window.__userInfoPromise = fetch('/api/user-info', { cache: 'no-store', credentials: 'same-origin', priority: 'low' })
        .then(function (r) {
            return r.json().then(function (body) {
                body = body || {};
                body.__status = r.status;
                return body;
            });
        })
        .catch(function () { return { __status: 0 }; });
})();

document.addEventListener('DOMContentLoaded', function () {
    window.__userInfoPromise && window.__userInfoPromise.then(function (data) {
        if (! data) return;
        window.userInfo = data;

        if (data.isLoggedIn) {
            document.cookie = "user_logged_in=1; max-age=86400; path=/";
        }
        if (data.name && data.name !== 'Ziyaretçi') {
            var w1 = document.querySelector('.welcome-message');
            var w2 = document.querySelector('.welcome-profile');
            if (w1) w1.innerText = 'Profiliniz';
            if (w2) { w2.innerText = 'Profiliniz'; w2.href = data.profile_url; }
        }

        var p = window.__post;
        var subEnabled = (data.subscriptionStatus === 1);
        if (p && p.private === 1 && subEnabled) {
            var feats = Array.isArray(data.accessibleFeatures) ? data.accessibleFeatures : [];
            var canAccess = feats.indexOf(p.type) !== -1 || feats.indexOf(String(p.type)) !== -1;
            if (! canAccess) {
                var msg = data.isLoggedIn ? 'Bu içerik için aboneliğiniz yetersiz.' : 'Bu içerik sadece abonelere özeldir. Lütfen giriş yapın.';
                var modal = document.querySelector('.error-modal');
                var msgEl = document.querySelector('.error-modal-message');
                if (modal) {
                    if (msgEl) msgEl.innerText = msg;
                    modal.style.display = 'flex';
                    modal.classList.remove('hidden');
                    document.body.style.overflow = 'hidden';
                }
            }
        }
    });

    if (typeof showUserMenu === 'function') {
        showUserMenu("https://www.canakkalekalem.com/profile", "https://www.canakkalekalem.com/logout", "https://www.canakkalekalem.com/login");
    }
});

(() => {
  const LS_KEY = 'adblock_banner_until';
  const ls = {
    get() { try { return +localStorage.getItem(LS_KEY) || 0; } catch { return 0; } },
    set(v){ try { localStorage.setItem(LS_KEY, String(v)); } catch {} }
  };

  window.__adblockCheck = window.__adblockCheck || null;

  window.adblockBanner = function () {
    return {
      open: false,

      async init() {
        const until = ls.get();
        if (until && Date.now() < until) return;

        if (!window.__adblockCheck) window.__adblockCheck = this.detectAdblock();
        const detected = await window.__adblockCheck;
        this.open = !!detected;
      },

      dismiss(hours = 24) {
        ls.set(Date.now() + hours * 3600 * 1000);
        this.open = false;
      },

      async detectAdblock() {
        const bait = document.createElement('div');
        bait.className = 'ad adsbox adsbygoogle banner-ad ad-placeholder sponsored';
        bait.style.cssText = 'width:1px;height:1px;position:absolute;left:-99999px;top:-99999px;';
        document.body.appendChild(bait);

        await new Promise(r => requestAnimationFrame(() => setTimeout(r, 50)));

        const cs = getComputedStyle(bait);
        const hidden =
                cs.display === 'none' ||
                cs.visibility === 'hidden' ||
                bait.offsetParent === null ||
                bait.offsetHeight === 0 ||
                bait.clientHeight === 0;

        bait.remove();
        return hidden;
      }
    }
  }
})();

(function() {
    function loadOnce(src) {
        if (document.querySelector('script[src="' + src + '"]')) return;
        var s = document.createElement('script');
        s.async = true;
        s.src = src;
        s.charset = 'utf-8';
        document.body.appendChild(s);
    }
    if (document.querySelector('blockquote.twitter-tweet')) {
        loadOnce('https://platform.twitter.com/widgets.js');
    }
    if (document.querySelector('blockquote.instagram-media')) {
        loadOnce('https://www.instagram.com/embed.js');
    }
    if (document.querySelector('blockquote.tiktok-embed')) {
        loadOnce('https://www.tiktok.com/embed.js');
    }
})();
